pub async fn inspect_entry(&self, entry_id: &str) -> Result<serde_json::Value> {
        let resp = self
            .client
            .get(format!("{}/v1/entries/{}/inspect", self.base_url, entry_id))
            .send()
            .await?
            .error_for_status()?;
        Ok(resp.json().await?)
    }
